class Person {
  constructor(name) {
    this.name = name;
    this.children = [];
    this.isAlive = true;
  }
}

class Monarchy {
  constructor(kingName) {
    this.king = new Person(kingName);
    this.people = { [kingName]: this.king };
  }

  birth(childName, parentName) {
    const parent = this.people[parentName];
    const child = new Person(childName);
    parent.children.push(child);
    this.people[childName] = child;
  }

  death(name) {
    if (this.people[name]) this.people[name].isAlive = false;
  }

  getOrderOfSuccession() {
    const order = [];
    const dfs = (person) => {
      if (!person) return;
      if (person.isAlive) order.push(person.name);
      for (const child of person.children) dfs(child);
    };
    dfs(this.king);
    return order;
  }
}

public class Monarchy
{
    private class Person
    {
        public string Name;
        public bool IsAlive = true;
        public List<Person> Children = new List<Person>();
        public Person(string name) { Name = name; }
    }

    private readonly Person king;
    private readonly Dictionary<string, Person> people = new Dictionary<string, Person>();

    public Monarchy(string kingName)
    {
        king = new Person(kingName);
        people[kingName] = king;
    }

    public void birth(string childName, string parentName)
    {
        var parent = people[parentName];
        var child = new Person(childName);
        parent.Children.Add(child);
        people[childName] = child;
    }

    public void death(string name)
    {
        if (people.TryGetValue(name, out var person)) person.IsAlive = false;
    }

    public IList<string> getOrderOfSuccession()
    {
        var order = new List<string>();

        void Dfs(Person p)
        {
            if (p == null) return;
            if (p.IsAlive) order.Add(p.Name);
            foreach (var child in p.Children) Dfs(child);
        }

        Dfs(king);
        return order;
    }
}

class Person:
    def __init__(self, name):
        self.name = name
        self.children = []
        self.is_alive = True


class Monarchy:
    def __init__(self, kingName):
        self.king = Person(kingName)
        self.people = {kingName: self.king}

    def birth(self, childName, parentName):
        parent = self.people[parentName]
        child = Person(childName)
        parent.children.append(child)
        self.people[childName] = child

    def death(self, name):
        if name in self.people:
            self.people[name].is_alive = False

    def getOrderOfSuccession(self):
        order = []

        def dfs(person):
            if not person:
                return
            if person.is_alive:
                order.append(person.name)
            for child in person.children:
                dfs(child)

        dfs(self.king)
        return order

